set-variable.value:
@{
            var h = context.Request.Headers.GetValueOrDefault("Authorization", "");
            if (h.Length < 20)
            {
                return h;
            }

            return h.Substring(0, 15) + "...(" + h.Length + " chars)";
        }

@{
            var h = context.Request.Headers.GetValueOrDefault("Authorization", "");
            return h.StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase) ? h.Substring(7) : h;
        }

@{
            var token = (string)context.Variables["incomingJwt"];
            var segments = token.Split('.');
            if (segments.Length < 2)
            {
                return "invalid";
            }

            var payload = segments[1].Replace('-', '+').Replace('_', '/');
            switch (payload.Length % 4)
            {
                case 2:
                    payload += "==";
                    break;
                case 3:
                    payload += "=";
                    break;
            }

            var claimsJson = Encoding.UTF8.GetString(Convert.FromBase64String(payload));
            var claims = JObject.Parse(claimsJson);

            var delegatedScopes = ((string)claims["scp"] ?? string.Empty)
                .Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
            if (delegatedScopes.Any(scope =>
                string.Equals(scope, "mcp.access", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(scope, "user_impersonation", StringComparison.OrdinalIgnoreCase)))
            {
                return "delegated";
            }

            var rolesClaim = claims["roles"];
            if (rolesClaim != null)
            {
                if (rolesClaim.Type == JTokenType.Array && rolesClaim.Any(role => string.Equals((string)role, "access_as_application", StringComparison.OrdinalIgnoreCase)))
                {
                    return "application";
                }

                if (rolesClaim.Type != JTokenType.Array && string.Equals((string)rolesClaim, "access_as_application", StringComparison.OrdinalIgnoreCase))
                {
                    return "application";
                }
            }

            return "insufficient";
        }

@{
            var jwt = ((string)context.Variables["incomingJwt"]).AsJwt();
            if (jwt == null)
            {
                return "";
            }

            if (jwt.Claims.ContainsKey("azp") && jwt.Claims["azp"].Length > 0)
            {
                return jwt.Claims["azp"][0];
            }

            if (jwt.Claims.ContainsKey("appid") && jwt.Claims["appid"].Length > 0)
            {
                return jwt.Claims["appid"][0];
            }

            return "";
        }

when.condition:
@{
                var callerId = (string)context.Variables["mcpCallerClientId"];
                if (string.IsNullOrWhiteSpace(callerId))
                {
                    return true;
                }

                var allowedClientIds = "{{McpAllowedCallerAppIdsCsv}}"
                    .Split(new[] { ';' }, StringSplitOptions.RemoveEmptyEntries)
                    .Select(appId => appId.Trim());

                return !allowedClientIds.Any(appId => string.Equals(appId, callerId, StringComparison.OrdinalIgnoreCase));
            }

set-header.value:
@{
                var jwt = (string)context.Variables["incomingJwt"];
                if (string.IsNullOrEmpty(jwt))
                {
                    return "";
                }

                var token = jwt.AsJwt();
                return token != null && token.Claims.ContainsKey("oid") && token.Claims["oid"].Length > 0
                    ? token.Claims["oid"][0]
                    : "";
            }

@{
                var jwt = (string)context.Variables["incomingJwt"];
                if (string.IsNullOrEmpty(jwt))
                {
                    return "";
                }

                var token = jwt.AsJwt();
                return token != null && token.Claims.ContainsKey("preferred_username") && token.Claims["preferred_username"].Length > 0
                    ? token.Claims["preferred_username"][0]
                    : "";
            }
